solution: class Solution {
public:
    int calculate(string s) {
        long long num = 0, n = s.size();
        char op = '+';
        stack<long long> st;
        for (int i = 0; i < n; ++i) {
            if (s[i] >= '0' && s[i] <= '9') {
                num = num * 10 + (s[i] - '0');
            }
            if ((s[i] < '0' && s[i] != ' ') || i == n - 1) {
                if (op == '+') st.push(num);
                else if (op == '-') st.push(-num);
                else if (op == '*') {
                    long long top = st.top(); st.pop();
                    st.push(top * num);
                } else if (op == '/') {
                    long long top = st.top(); st.pop();
                    st.push(top / num);
                }
                op = s[i];
                num = 0;
            }
        }
        long long res = 0;
        while (!st.empty()) {
            res += st.top();
            st.pop();
        }
        return static_cast<int>(res);
    }
};
